const customers = $input.all().map(i => i.json);
const threshold = Math.floor(customers.length * 0.2);
const vipCandidates = customers.slice(0, threshold);
// Only upgrade customers not already VIP
const newVips = vipCandidates.filter(c => c.tier !== 'vip');

if (newVips.length === 0) return [{ json: { _skip: true } }];

return newVips.map(c => {
  const name = c.first_name || 'Valued Customer';
  const subject = "You're a TotalGuard VIP!";
  const body = `Hi ${name},\n\nAs one of our most valued customers, we're upgrading you to VIP status! Your benefits:\n\n- Priority scheduling\n- 10% loyalty discount on all services\n- Free seasonal consultation\n- Early access to seasonal booking\n\nThank you for trusting TotalGuard with your yard!\n\n- The TotalGuard Team`;

  const htmlBody = buildEmailHtml({
    subject,
    headline: `Congratulations, ${name}! You're now a TotalGuard VIP`,
    bodyHtml: `<p>Hi ${name},</p><p>As one of our most valued customers, we're thrilled to upgrade you to <strong style="color:#C5A55A;">VIP status</strong>! This is our way of saying thank you for your loyalty and trust.</p><p style="font-size:16px;font-weight:bold;color:#2D5A27;margin-bottom:4px;">Your Exclusive VIP Benefits:</p><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:16px;"><tr><td style="padding:8px 0;border-bottom:1px solid #eee;"><span style="color:#2D5A27;font-weight:bold;">\u2705</span> <strong>Priority Scheduling</strong> — Your jobs get scheduled first, guaranteed</td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #eee;"><span style="color:#2D5A27;font-weight:bold;">\u2705</span> <strong>10% Loyalty Discount</strong> — On every service, automatically applied</td></tr><tr><td style="padding:8px 0;border-bottom:1px solid #eee;"><span style="color:#2D5A27;font-weight:bold;">\u2705</span> <strong>Free Seasonal Consultation</strong> — Personalized yard care plan each season</td></tr><tr><td style="padding:8px 0;"><span style="color:#2D5A27;font-weight:bold;">\u2705</span> <strong>Early Access</strong> — Book seasonal services before anyone else</td></tr></table><p>These benefits are active on your account <strong>right now</strong>. No action needed — just keep being the amazing customer you are!</p>`,
    reviewText: 'Been with TotalGuard for over two years now. The VIP treatment is real — they always prioritize my property and the results are consistently outstanding.',
    reviewerName: 'Robert & Karen W., Middleton',
    ctaText: 'Explore VIP Services',
    ctaUrl: 'https://tgyardcare.com',
    urgencyText: '\u{1F31F} Your VIP benefits are active now — 10% off is automatically applied to your next service!',
    previewText: `Congratulations ${name}! You've been upgraded to TotalGuard VIP status with exclusive benefits.`
  });

  return { json: { ...c, subject, body, htmlBody } };
});
